sql:
SELECT user_id, COUNT(trade_id) AS trade_count
FROM trades
WHERE user_id = 123;

SELECT stock_id, MAX(price_change_percentage) AS highest_price_change_percentage
FROM intraday_prices
GROUP BY stock_id;

external_knowledge:
- Ambitious voyagers: Users who conducted trades;
- Vast oceans: The stock market;
- Grand ships: Companies whose stocks were traded;
- Voyage: A trade made on a specific date;
- Precious cargos: Shares traded;
- More than a thousand: Quantity of shares traded > 1000.

sql:
SELECT datetime, open_price, close_price
FROM intraday_prices
WHERE stock_id > 500 AND open_price > 100;
